package tests;import base.BaseTest;import pages.CocineroPage;import pages.LoginPage;import org.junit.jupiter.api.Assertions;import org.junit.jupiter.api.Test;public class HP05FlujoCompletoEstadosTest extends BaseTest {    @Test    void flujoCompletoDeEstadosPedido() {        try {            System.out.println("Ejecutando HP-05: Flujo completo de estados");            LoginPage loginPage = new LoginPage(driver);            loginPage.abrirLogin();            loginPage.iniciarSesion("cocinero", "123");            Thread.sleep(3000);            CocineroPage cocineroPage = new CocineroPage(driver);            int pendientesAntes = cocineroPage.cantidadBotonesComenzarPreparacion();            int preparacionAntes = cocineroPage.cantidadBotonesMarcarComoEntregado();            Assertions.assertTrue(                    pendientesAntes > 0,                    "No existe ningún pedido pendiente para iniciar el flujo completo."            );            cocineroPage.comenzarPreparacion();            Thread.sleep(3000);            int pendientesDespues = cocineroPage.cantidadBotonesComenzarPreparacion();            int preparacionDespues = cocineroPage.cantidadBotonesMarcarComoEntregado();            Assertions.assertTrue(                    pendientesDespues < pendientesAntes,                    "El pedido no salió correctamente de la sección Pendientes."            );            Assertions.assertTrue(                    preparacionDespues > preparacionAntes,                    "El pedido no ingresó correctamente a la sección En Preparación."            );            cocineroPage.marcarComoEntregado();            Thread.sleep(3000);            int preparacionFinal = cocineroPage.cantidadBotonesMarcarComoEntregado();            Assertions.assertTrue(                    preparacionFinal < preparacionDespues,                    "El pedido no fue entregado correctamente desde En Preparación."            );            System.out.println("HP-05 ejecutado correctamente.");        } catch (Exception e) {            Assertions.fail("Error en HP-05: " + e.getMessage());        }    }}